<template>
  <div style="width: 40%; margin-left: 200px">
    <div style="margin-bottom: 50px; margin-left: 280px" >编辑楼层</div>
    <el-form :model="form" :rules="rules" ref="ruleForm" label-width="200px">
      <el-form-item label="楼层" prop="floor">
        <el-input-number v-model="form.floor"  :min="1" :max="10" ></el-input-number>
      </el-form-item>
      <el-form-item label="区域" prop="area">
        <el-input v-model="form.area" placeholder="请输入区域"></el-input>
      </el-form-item>
      <el-form-item label="管理员编号" prop="admin">
        <el-cascader
            :props="{value: 'id', label: 'id'}"
            v-model="form.admins"
            :options="admins"
            @change="handleChange"></el-cascader>
      </el-form-item>
    </el-form>
    <div style="margin-left: 250px; margin-top: 40px">
      <el-button type="primary" @click="save">提交</el-button>
      <el-button style="background-color: #f3d19e; color: white" @click="change">返回</el-button>
      <!--            <el-button type="danger ">取消</el-button>-->
    </div>
  </div>
</template>

<script>
import request from "@/utils/request";
//导入请求
export default {
  name: "AddPublish",
  data(){

    // 自定义的校验
    return {
      form: {

      },
      admins:[],
      rules: {},

    }

  },
  created() {
    request.get('/admin/list').then(res => {
      this.admins = res.data;//表单外的admin
    })
    const id = this.$route.query.id
    request.get("/location/" + id).then(res =>{

      this.form = res.data
      // if(this.form.admin)//从后台请求来的数据
      // this.form.admins  = this.form.admin;
    })

  },
  methods: {
    save() {
      request.put('/location/update',this.form).then(res =>{
        if(res.code === '200'){
          this.$notify.success('更新成功')
          this.$router.push("/locationList")
        }else{
          this.$notify.error(res.msg)
        }
      })
    },
    change(){
      this.$router.push('locationList')
    },
    handleChange(){

    }
  }
}
</script>

